  }, [dateFrom, dateTo, selectedSalon?.id]);

  const chartConfig =
    dashboardData?.topServices.reduce(
      (acc, service) => {
        acc[service.name] = {
          label: service.name,
          color: service.color,
        };
        return acc;
      },
      { ...defaultChartConfig }
