                  <>
                    <ChartContainer
                      config={chartConfig}
                      className="mx-auto aspect-square max-h-[350px] w-full max-w-[350px] overflow-hidden"
                    >
                      <PieChart>
                        <ChartTooltip
                          cursor={false}
                          content={<ChartTooltipContent hideLabel />}
                        />
                        <Pie
                          data={dashboardData.topServices}
                          dataKey="value"
                          nameKey="name"
                          cx="50%"
                          cy="50%"
                          outerRadius="80%"
                          innerRadius="50%"
                          strokeWidth={2}
                        >
                          {dashboardData.topServices.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={entry.color} />
                          ))}
                        </Pie>
                      </PieChart>
                    </ChartContainer>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-x-6 gap-y-2 mt-6 w-full max-w-full">
                      {dashboardData.topServices.map((item, index) => (
                        <div key={index} className="flex items-center gap-2 min-w-0">
                          <div
                            className="w-3 h-3 rounded-full shrink-0"
                            style={{ backgroundColor: item.color }}
                          />
