import * as React from "react"
import { Calendar, Clock } from "lucide-react"

import { cn } from "@/lib/utils"
import { Label } from "@/components/ui/label"

interface InputProps extends React.ComponentProps<"input"> {
  label?: string;
}

const Input = React.forwardRef<HTMLInputElement, InputProps>(
  ({ className, type, label, id, required, ...props }, ref) => {
    const generatedId = React.useId();
    const inputId = id ?? generatedId;

    const inputElement = (
      <input
        id={inputId}
        type={type}
        required={required}
        className={cn(
          "flex h-10 w-full rounded-[12px] border border-input bg-background px-3 py-2 text-[13px] ring-offset-background file:border-0 file:bg-transparent file:text-[13px] file:font-medium file:text-foreground placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50",
          (type === "date" || type === "time") && "[&::-webkit-calendar-picker-indicator]:opacity-0 [&::-webkit-calendar-picker-indicator]:absolute [&::-webkit-calendar-picker-indicator]:w-full pr-8",
          className
        )}
        ref={ref}
        {...props}
      />
    );

    const wrappedElement = type === "date" ? (
      <div className="relative">
        {inputElement}
        <Calendar className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
      </div>
    ) : type === "time" ? (
      <div className="relative">
        {inputElement}
        <Clock className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
      </div>
    ) : inputElement;

    if (label) {
      return (
        <div className="flex flex-col gap-[4px]">
          <Label htmlFor={inputId}>{label}{required && <span className="text-destructive ml-0.5">*</span>}</Label>
          {wrappedElement}
        </div>
      );
    }

    return wrappedElement;
  }
)
Input.displayName = "Input"

export { Input }
export type { InputProps }

