7	import { PlanActivationSuccessModal } from "@/components/salon/subscription/PlanActivationSuccessModal";
8	import { PlanSelection } from "@/components/salon/subscription/PlanSelection";
9	import { PurchaseSummary } from "@/components/salon/subscription/PurchaseSummary";
10	import { SubscriptionConfirmationModal } from "@/components/salon/subscription/SubscriptionConfirmationModal";
11	import { SubscriptionStatusCard } from "@/components/salon/subscription/SubscriptionStatusCard";
12	import { getSalonNavItems } from "@/config/navigation";
13	import { useAuth } from "@/contexts/AuthContext";
