27	export default function MyPlanPage() {
28	    const { user } = useAuth();
29	    const { selectedSalon } = useSelectedSalon();
30	
31	    const [loading, setLoading] = useState(true);
32	    const [billingState, setBillingState] = useState<CurrentSubscriptionResponse | null>(null);
33	    const [plans, setPlans] = useState<Plan[]>([]);
34	    const [selectedPlanId, setSelectedPlanId] = useState<string | undefined>();
35	    const [activating, setActivating] = useState(false);
36	    const [isChangePlanModalOpen, setIsChangePlanModalOpen] = useState(false);
37	    const [isCancelModalOpen, setIsCancelModalOpen] = useState(false);
38	    const [isDeleteCardModalOpen, setIsDeleteCardModalOpen] = useState(false);
39	    const [isDeletingCard, setIsDeletingCard] = useState(false);
40	    const [showSuccess, setShowSuccess] = useState(false);
41	    const [isConfirmationModalOpen, setIsConfirmationModalOpen] = useState(false);
42	    const [pendingPaymentMethod, setPendingPaymentMethod] = useState<any>(null);
43	
44	    // Get navigation items
45	    const navItems = getSalonNavItems(user?.role || "Administrador", 0);
46	
47	    const fetchData = async (): Promise<CurrentSubscriptionResponse | null> => {
48	        if (!selectedSalon) return null;
49	        try {
50	            setLoading(true);
51	            // Fetch subscription and plans in parallel
52	            const [state, plansData] = await Promise.all([
53	                subscriptionService.getCurrentSubscription(selectedSalon.id),
54	                planService.list()
55	            ]);
56	            setBillingState(state);
57	            setPlans(plansData);
58	
59	            // Auto select current plan or default to first valid plan if none
60	            if (state?.subscription?.planId) {
61	                setSelectedPlanId(state.subscription.planId);
62	            } else if (plansData.length > 0 && !selectedPlanId) {
63	                // Only default if NOT already selected (user might have clicked a plan before adding card)
64	                // Prefer "Plano IA" if available
65	                const defaultPlan = plansData.find(p => p.slug === 'plano-ia') || plansData[0];
66	                setSelectedPlanId(defaultPlan.id);
67	            }
68	            return state;
69	
70	        } catch (error) {
71	            console.error("Failed to fetch subscription data", error);
72	            toast.error("Erro ao carregar dados da assinatura");
73	            return null;
74	        } finally {
75	            setLoading(false);
76	        }
77	    };
78	
79	    useEffect(() => {
80	        fetchData();
81	    }, [selectedSalon]);
82	
83	    const handleUpdatePaymentMethod = async (cardData: any) => {
84	        if (!selectedSalon) return;
85	        try {
86	            // Pass user data to improve payer information
87	            await subscriptionService.updatePaymentMethod(
88	                selectedSalon.id,
89	                cardData,
90	                user?.email,
91	                user?.name
92	            );
93	            toast.success("Método de pagamento atualizado!");
94	
95	            // Refresh state to get the new card
96	            const newState = await fetchData();
97	
98	            // AUTO-ACTIVATION FLOW -> CONFIRMATION MODAL
99	            if (newState) {
100	                const newStatus = newState.status || 'none';
101	                const newValidUntil = newState.subscription?.validUntil ? parseISO(newState.subscription.validUntil.toString()) : null;
102	                const newIsCanceling = !!(newState.subscription?.cancelAtPeriodEnd && newValidUntil && isAfter(newValidUntil, new Date()));
103	
104	                const newIsExpiredOrPastDue = (newStatus === 'past_due' || newStatus === 'canceled') && !newIsCanceling;
105	                const newIsNone = newStatus === 'none';
106	                const shouldTriggerFlow = newIsExpiredOrPastDue || newIsNone;
107	
108	                if (shouldTriggerFlow && selectedPlanId) {
109	                    // Store the payment method to be used in activation
110	                    setPendingPaymentMethod(newState.defaultPaymentMethod);
111	                    // Open confirmation modal instead of activating directly
112	                    setIsConfirmationModalOpen(true);
113	                }
114	            }
115	
116	        } catch (e: any) {
117	            const errorMessage = e?.response?.data?.message || e?.message || "Erro ao atualizar cartão. Tente novamente.";
118	            toast.error(errorMessage);
119	        }
120	    };
121	
122	    const handleCancelSubscription = () => {
123	        if (billingState?.actions.canCancel) {
124	            setIsCancelModalOpen(true);
125	        }
126	    };
127	
128	    const handleConfirmCancel = async () => {
129	        if (!selectedSalon) return;
130	
131	        try {
132	            await subscriptionService.cancelSubscription(selectedSalon.id);
133	            toast.success("Assinatura cancelada.");
134	            await fetchData();
135	        } catch (e) {
136	            toast.error("Erro ao cancelar assinatura.");
137	        }
138	    };
139	
140	    const handleChangePlan = () => {
141	        if (billingState?.actions.canChangePlan) {
142	            setIsChangePlanModalOpen(true);
143	        }
144	    };
