155	        if (!selectedPlanId || !selectedSalon) {
156	            toast.error("Selecione um plano para continuar.");
157	            return;
158	        }
159	        if (!user?.email) {
160	            toast.error("Email do usuário não encontrado. Faça login novamente.");
161	            return;
162	        }
163	
164	        // Use custom method (from auto-activation) or fallback to state
165	        // Safety: If it's a React event (from direct onClick), ignore it
166	        const isEvent = customPaymentMethod && (customPaymentMethod.nativeEvent || customPaymentMethod._reactName);
167	        const methodToUse = (customPaymentMethod && !isEvent) ? customPaymentMethod : displayPaymentMethod;
168	
169	        if (!methodToUse) {
170	            toast.error("Adicione um cartão de crédito para continuar.");
171	            return;
172	        }
173	
174	        if (!methodToUse.payerDoc || !methodToUse.payerType) {
175	            toast.error("Dados do pagador incompletos. Atualize o cartão de crédito.");
176	            return;
177	        }
178	
179	        try {
180	            setActivating(true);
181	            const payload: CreateSubscriptionDto = {
182	                salonId: selectedSalon.id,
183	                planId: selectedPlanId,
184	                card: {
185	                    cardId: methodToUse.id,
186	                    holderName: methodToUse.holderName,
187	                    expirationDate: methodToUse.expirationDate,
188	                    brand: methodToUse.brand,
189	                },
190	                payer: {
191	                    name: methodToUse.payerName || methodToUse.holderName,
192	                    email: user.email,
193	                    document: methodToUse.payerDoc,
194	                    type: methodToUse.payerType,
195	                    address: methodToUse.payerAddress ? {
196	                        street: methodToUse.payerAddress.street,
197	                        number: methodToUse.payerAddress.number,
198	                        zipCode: methodToUse.payerAddress.zipCode,
199	                        city: methodToUse.payerAddress.city,
