205	
206	            await subscriptionService.createSubscription(payload);
207	            setShowSuccess(true);
208	            subscriptionState.setExpired(false);
209	
210	            trackSeverinoEvent('pagamento_realizado', {
211	                description: "Pagamento realizado / Plano ativado",
212	                planId: selectedPlanId,
213	                salonId: selectedSalon.id
214	            });
215	
216	            fetchData();
217	        } catch (err: any) {
218	            const errorMessage = err?.response?.data?.message || err?.message || "Erro ao ativar plano. Tente novamente.";
219	            toast.error(errorMessage);
220	        } finally {
221	            setActivating(false);
222	        }
223	    };
224	
225	    const handleDeletePaymentMethod = () => {
226	        setIsDeleteCardModalOpen(true);
227	    };
228	
229	    const handleConfirmDeleteCard = async () => {
230	        if (!displayPaymentMethod) return;
231	        try {
232	            setIsDeletingCard(true);
