240	            setIsDeletingCard(false);
241	        }
242	    };
243	
244	    const handleConfirmActivation = async () => {
245	        await handleActivatePlan(pendingPaymentMethod);
246	        setIsConfirmationModalOpen(false);
247	        setPendingPaymentMethod(null);
