import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { DataTable, Column } from "@/components/ui/data-table";
import { Invoice } from "@/types/subscription";
import { differenceInDays, format, parseISO } from "date-fns";
import { ptBR } from "date-fns/locale";
import { AlertCircle as AlertCircle, Calendar as Calendar, Check as Check, ReceiptText as ReceiptText, X as X } from "lucide-react";
import { useMemo, useState } from "react";

interface PaymentHistoryTableProps {
    history: Invoice[];
    showActions?: boolean; // Optional prop if we want to enable it later
}

type PeriodFilter = 'all' | '30' | '90';

export function PaymentHistoryTable({ history, showActions = false }: PaymentHistoryTableProps) {
    const [periodFilter, setPeriodFilter] = useState<PeriodFilter>('all');

    const filteredHistory = useMemo(() => {
        let items = history;
        if (periodFilter !== 'all') {
            const now = new Date();
            const days = parseInt(periodFilter);
            items = history.filter(item => {
                const date = parseISO(item.createdAt);
                return differenceInDays(now, date) <= days;
            });
        }
        return items;
    }, [history, periodFilter]);

    const getFilterLabel = () => {
        switch (periodFilter) {
            case '30': return 'Últimos 30 dias';
            case '90': return 'Últimos 90 dias';
            default: return 'Todos os períodos';
        }
    };

    const columns: Column<Invoice>[] = [
        {
            key: "createdAt" as keyof Invoice,
            header: "Data",
            render: (value: string) => format(parseISO(value), 'dd/MM/yyyy', { locale: ptBR }),
        },
        {
            key: "plan" as keyof Invoice,
            header: "Plano",
            render: (_, row: Invoice) => row.subscription?.plan?.name || "-",
        },
        {
            key: "amount" as keyof Invoice,
            header: "Valor",
            render: (value: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Number(value)),
        },
        {
            key: "paymentMethod" as keyof Invoice,
            header: "Método",
            render: (_, row: Invoice) =>
                row.subscription?.paymentMethod ?
                    `Cartão •••• ${row.subscription.paymentMethod.last4}` :
                    "-",
        },
        {
            key: "status" as keyof Invoice,
            header: "Status",
            render: (value: string) => <StatusBadge status={value} />,
        },
    ];

    if (filteredHistory.length === 0) {
        return (
            <div className="space-y-4">
                <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                    <h2 className="text-xl font-medium text-foreground flex items-center gap-2">
                        <ReceiptText className="w-5 h-5" />
                        Histórico de Pagamentos
                    </h2>

                    <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <Button
                                variant="outline"
                                size="sm"
                                className="transition-all cursor-pointer shadow-xs dark:bg-input/30 dark:border-input dark:hover:bg-input/50 gap-1.5"
                            >
                                <Calendar className="w-4 h-4 mr-2" />
                                {getFilterLabel()}
                            </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                            <DropdownMenuItem onClick={() => setPeriodFilter('all')}>
                                Todos os períodos
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => setPeriodFilter('30')}>
                                Últimos 30 dias
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => setPeriodFilter('90')}>
                                Últimos 90 dias
                            </DropdownMenuItem>
                        </DropdownMenuContent>
                    </DropdownMenu>
                </div>

                <div className="salon-card p-8 text-center text-muted-foreground">
                    Nenhum histórico encontrado para este período.
                </div>
            </div>
        );
    }

    return (
        <div className="space-y-4">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                <h2 className="text-xl font-medium text-foreground flex items-center gap-2">
                    <ReceiptText className="w-5 h-5" />
                    Histórico de Pagamentos
                </h2>

                <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                        <Button
                            variant="outline"
                            size="sm"
                            className="transition-all cursor-pointer shadow-xs dark:bg-input/30 dark:border-input dark:hover:bg-input/50 gap-1.5"
                        >
                            <Calendar className="w-4 h-4 mr-2" />
                            {getFilterLabel()}
                        </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end">
                        <DropdownMenuItem onClick={() => setPeriodFilter('all')}>
                            Todos os períodos
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => setPeriodFilter('30')}>
                            Últimos 30 dias
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => setPeriodFilter('90')}>
                            Últimos 90 dias
                        </DropdownMenuItem>
                    </DropdownMenuContent>
                </DropdownMenu>
            </div>

            <DataTable
                data={filteredHistory}
                columns={columns}
                mobileView="cards"
                mobileCardConfig={{
                    title: (row: Invoice) => format(parseISO(row.createdAt), 'dd/MM/yyyy', { locale: ptBR }),
                    subtitle: (row: Invoice) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Number(row.amount)),
                    badge: (row: Invoice) => <StatusBadge status={row.status} />,
                    excludeFromGrid: ["createdAt", "amount", "status"],
                }}
                pageSize={5}
            />
        </div>
    );
}

function StatusBadge({ status }: { status: string }) {
    if (status === 'paid' || status === 'PAID') {
        return (
            <span className="px-2 py-1 text-xs font-medium text-green-700 bg-green-50 flex items-center gap-1 w-fit rounded-full">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" className="tabler-icon tabler-icon-check w-3 h-3">
                    <path d="M5 12l5 5l10 -10"></path>
                </svg>
                Pago
            </span>
        );
    }
    if (status === 'open' || status === 'OPEN') {
        return (
            <span className="px-2 py-1 text-xs font-medium text-yellow-700 bg-yellow-50 flex items-center gap-1 w-fit rounded-full">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" className="tabler-icon tabler-icon-alert-circle w-3 h-3">
                    <circle cx="12" cy="12" r="9"></circle>
                    <line x1="12" y1="8" x2="12" y2="12"></line>
                    <line x1="12" y1="16" x2="12.01" y2="16"></line>
                </svg>
                Aberto
            </span>
        );
    }
    return (
        <span className="px-2 py-1 text-xs font-medium text-red-700 bg-red-50 flex items-center gap-1 w-fit rounded-full">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" className="tabler-icon tabler-icon-x w-3 h-3">
                <path d="M18 6l-12 12"></path>
                <path d="M6 6l12 12"></path>
            </svg>
            {status}
        </span>
    );
}
